import{_ as t,o as h,c as a,a0 as i}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"Số dư đầu kỳ","description":"","frontmatter":{"title":"Số dư đầu kỳ"},"headers":[],"relativePath":"opening-balance.md","filePath":"opening-balance.md"}'),o={name:"opening-balance.md"};function c(r,n,s,l,u,d){return h(),a("div",null,[...n[0]||(n[0]=[i('<h1 id="so-du-đau-ky" tabindex="-1">Số dư đầu kỳ <a class="header-anchor" href="#so-du-đau-ky" aria-label="Permalink to &quot;Số dư đầu kỳ&quot;">​</a></h1><p><strong>Số dư đầu kỳ (Opening Balance)</strong> là số dư của các tài khoản kế toán tại thời điểm bắt đầu sử dụng ABNERP hoặc đầu năm tài chính. Thiết lập số dư đầu kỳ chính xác là nền tảng để hệ thống kế toán vận hành đúng đắn và báo cáo tài chính phản ánh trung thực tình hình doanh nghiệp.</p><h2 id="khi-nao-can-thiet-lap" tabindex="-1">Khi nào cần thiết lập? <a class="header-anchor" href="#khi-nao-can-thiet-lap" aria-label="Permalink to &quot;Khi nào cần thiết lập?&quot;">​</a></h2><ul><li><strong>Triển khai ABNERP lần đầu</strong>: chuyển đổi dữ liệu kế toán từ hệ thống hoặc phần mềm cũ</li><li><strong>Đầu năm tài chính</strong>: nhập số dư của các tài khoản cho năm tài chính mới</li><li><strong>Công ty mới</strong>: thiết lập số dư ban đầu khi thành lập công ty</li></ul><h2 id="quy-trinh-thiet-lap" tabindex="-1">Quy trình thiết lập <a class="header-anchor" href="#quy-trinh-thiet-lap" aria-label="Permalink to &quot;Quy trình thiết lập&quot;">​</a></h2><h3 id="buoc-1-chuan-bi-bang-can-đoi-thu" tabindex="-1">Bước 1: Chuẩn bị bảng cân đối thử <a class="header-anchor" href="#buoc-1-chuan-bi-bang-can-đoi-thu" aria-label="Permalink to &quot;Bước 1: Chuẩn bị bảng cân đối thử&quot;">​</a></h3><p>Trước khi nhập, cần chuẩn bị <strong>Bảng cân đối thử (Trial Balance)</strong> tại thời điểm chốt — với số dư Nợ và số dư Có của tất cả tài khoản kế toán. Đảm bảo tổng số dư Nợ bằng tổng số dư Có trước khi nhập vào ABNERP.</p><h3 id="buoc-2-nhap-so-du-đau-ky" tabindex="-1">Bước 2: Nhập số dư đầu kỳ <a class="header-anchor" href="#buoc-2-nhap-so-du-đau-ky" aria-label="Permalink to &quot;Bước 2: Nhập số dư đầu kỳ&quot;">​</a></h3><p>Vào <strong>Kế toán &gt; Công cụ &gt; Nhập số dư đầu kỳ</strong>. Các bước thực hiện:</p><ol><li><strong>Chọn năm tài chính</strong>: chọn năm tài chính áp dụng cho số dư đầu kỳ</li><li><strong>Nhập số dư cho từng tài khoản</strong>: có thể nhập thủ công hoặc nhập từ tệp Excel</li><li><strong>Xác nhận cân đối</strong>: hệ thống tự động kiểm tra tổng Nợ = tổng Có</li></ol><h3 id="buoc-3-kiem-tra-va-xac-nhan" tabindex="-1">Bước 3: Kiểm tra và xác nhận <a class="header-anchor" href="#buoc-3-kiem-tra-va-xac-nhan" aria-label="Permalink to &quot;Bước 3: Kiểm tra và xác nhận&quot;">​</a></h3><p>Sau khi nhập, kiểm tra lại số dư các tài khoản trong <strong>Sơ đồ tài khoản (Chart of Accounts)</strong>. Các tài khoản sẽ hiển thị số dư đầu kỳ trong các báo cáo kế toán.</p><h2 id="tai-khoan-can-thiet-lap" tabindex="-1">Tài khoản cần thiết lập <a class="header-anchor" href="#tai-khoan-can-thiet-lap" aria-label="Permalink to &quot;Tài khoản cần thiết lập&quot;">​</a></h2><p>Các tài khoản thường cần nhập số dư đầu kỳ bao gồm:</p><table tabindex="0"><thead><tr><th>Loại tài khoản</th><th>Ví dụ</th></tr></thead><tbody><tr><td><strong>Tài sản ngắn hạn</strong></td><td>Tiền mặt, Tiền gửi ngân hàng, Khoản phải thu khách hàng, Hàng tồn kho</td></tr><tr><td><strong>Tài sản dài hạn</strong></td><td>Tài sản cố định, Khấu hao lũy kế, Đầu tư tài chính</td></tr><tr><td><strong>Nợ phải trả</strong></td><td>Khoản phải trả người bán, Thuế phải nộp, Vay ngắn hạn</td></tr><tr><td><strong>Vốn chủ sở hữu</strong></td><td>Vốn góp, Lợi nhuận chưa phân phối</td></tr><tr><td><strong>Doanh thu/Chi phí</strong></td><td>Các tài khoản doanh thu và chi phí (nếu có số dư lũy kế)</td></tr></tbody></table><h3 id="luu-y-quan-trong" tabindex="-1">Lưu ý quan trọng <a class="header-anchor" href="#luu-y-quan-trong" aria-label="Permalink to &quot;Lưu ý quan trọng&quot;">​</a></h3><ul><li><strong>Cân đối bắt buộc</strong>: Tổng số dư Nợ phải bằng tổng số dư Có, nếu không hệ thống sẽ không cho phép lưu</li><li><strong>Tài khoản con</strong>: Nếu nhập số dư cho tài khoản cha, số dư sẽ tự động phân bổ cho các tài khoản con</li><li><strong>Không thay đổi sau khi duyệt</strong>: Sau khi đã duyệt và có giao dịch phát sinh, không nên sửa số dư đầu kỳ — hãy điều chỉnh bằng bút toán điều chỉnh</li><li><strong>Sao lưu dữ liệu</strong>: Luôn sao lưu cơ sở dữ liệu trước khi thực hiện nhập số dư đầu kỳ hàng loạt</li></ul>',17)])])}const p=t(o,[["render",c]]);export{g as __pageData,p as default};
